import React, { useEffect, useState } from "react";
import axios from "axios";

export default function Categorias() {
  const [categorias, setCategorias] = useState([]);
  const [productos, setProductos] = useState([]);
  const [categoriaSeleccionada, setCategoriaSeleccionada] = useState(null);

  useEffect(() => {
    obtenerCategorias();
  }, []);

  const obtenerCategorias = async () => {
    try {
      const res = await axios.get("http://localhost:5000/api/categorias");
      setCategorias(res.data);
    } catch (error) {
      console.error("❌ Error al obtener categorías:", error);
    }
  };

  const mostrarProductosPorCategoria = async (categoria) => {
    setCategoriaSeleccionada(categoria);
    try {
      const res = await axios.get(
        `http://localhost:5000/api/productos/categoria/${categoria.id}`
      );
      setProductos(res.data);
    } catch (error) {
      console.error("❌ Error al obtener productos:", error);
    }
  };

  return (
    <div className="container mt-5">
      <h2 className="text-center mb-5 fw-bold">Categorías</h2>

      {/* LISTA DE CATEGORÍAS */}
      <div className="row justify-content-center">
        {categorias.map((cat) => (
          <div key={cat.id} className="col-10 col-md-4 col-lg-3 mb-4">
            <div
              className={`card shadow-lg border-0 text-center p-4 ${
                categoriaSeleccionada?.id === cat.id
                  ? "bg-primary text-white"
                  : "bg-light"
              }`}
              style={{ cursor: "pointer", transition: "0.3s" }}
              onClick={() => mostrarProductosPorCategoria(cat)}
            >
              <h4 className="fw-bold">{cat.nombre}</h4>
              <p className="small mb-0">
                {cat.descripcion || "Sin descripción"}
              </p>
            </div>
          </div>
        ))}
      </div>

      {/* PRODUCTOS DE LA CATEGORÍA SELECCIONADA */}
      {categoriaSeleccionada && (
        <div className="mt-5">
          <h3 className="text-center mb-4">
            Productos en “{categoriaSeleccionada.nombre}”
          </h3>
          {productos.length > 0 ? (
            <div className="table-responsive">
              <table className="table table-bordered text-center align-middle">
                <thead className="table-dark">
                  <tr>
                    <th>ID</th>
                    <th>Nombre</th>
                    <th>Descripción</th>
                    <th>Precio</th>
                    <th>Stock</th>
                  </tr>
                </thead>
                <tbody>
                  {productos.map((p) => (
                    <tr key={p.id}>
                      <td>{p.id}</td>
                      <td>{p.nombre}</td>
                      <td>{p.descripcion}</td>
                      <td>${p.precio}</td>
                      <td>{p.stock}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          ) : (
            <p className="text-center text-muted">
              No hay productos en esta categoría.
            </p>
          )}
        </div>
      )}
    </div>
  );
}
